mapper.update:
update wvp_device_channel
    set sub_count = (
        select * from (select count(0) from wvp_device_channel where device_id = #{deviceId} and parent_id = #{channelId}) as temp
    )
where device_id = #{deviceId} and channel_id = #{channelId}

mapper.select:
SELECT  dc.*, de.name as device_name, de.on_line as device_online from wvp_device_channel dc
    LEFT JOIN wvp_device de ON dc.device_id = de.device_id

     AND dc.device_id = #{deviceId} 
     AND (dc.channel_id LIKE '%${query}%' OR dc.name LIKE '%${query}%' OR dc.name LIKE '%${query}%')
     AND dc.parent_id=#{parentChannelId} 
     AND dc.status=true
     AND dc.status=false
      AND dc.sub_count > 0 
      AND dc.sub_count = 0 
     AND dc.channel_id in

            #{item}



ORDER BY dc.channel_id ASC Limit #{limit} OFFSET #{start}

select * from wvp_device_channel

    device_id=#{deviceId}
     and parent_id = #{parentId} 
     and parent_id is null or parent_id = #{deviceId}
     and parental = 1

SELECT dc.id, dc.channel_id, dc.device_id, dc.name, de.manufacturer, de.host_address, dc.sub_count, pgc.platform_id as platform_id, pgc.catalog_id as catalog_id FROM wvp_device_channel dc LEFT JOIN wvp_device de ON dc.device_id = de.device_id LEFT JOIN wvp_platform_gb_channel pgc on pgc.device_channel_id = dc.id
AND (dc.channel_id LIKE concat('%',#{query},'%') OR dc.name LIKE concat('%',#{query},'%') OR dc.name LIKE concat('%',#{query},'%')) AND dc.status=true AND dc.status=false AND dc.sub_count > 0 AND dc.sub_count = 0 AND dc.id not in (select device_channel_id from wvp_platform_gb_channel where platform_id=#{platformId} ) AND pgc.platform_id = #{platformId} and pgc.catalog_id=#{catalogId}
ORDER BY dc.device_id, dc.channel_id ASC

SELECT dc.id, dc.channel_id, dc.device_id, dc.name, de.manufacturer, de.host_address, dc.sub_count, pgc.platform_id as platform_id, pgc.catalog_id as catalog_id FROM wvp_device_channel dc LEFT JOIN wvp_device de ON dc.device_id = de.device_id LEFT JOIN wvp_platform_gb_channel pgc on pgc.device_channel_id = dc.id
AND (dc.channel_id LIKE concat('%',#{query},'%') OR dc.name LIKE concat('%',#{query},'%') OR dc.name LIKE concat('%',#{query},'%')) AND dc.status=true AND dc.status=false AND dc.sub_count > 0 AND dc.sub_count = 0 AND dc.id not in (select device_channel_id from wvp_platform_gb_channel where platform_id=#{platformId} ) AND pgc.platform_id = #{platformId} and pgc.catalog_id=#{catalogId}
ORDER BY dc.device_id, dc.channel_id ASC

SELECT dc.* from wvp_device_channel dc WHERE dc.device_id = #{deviceId} AND (dc.channel_id LIKE concat('%',#{query},'%') OR dc.name LIKE concat('%',#{query},'%') OR dc.name LIKE concat('%',#{query},'%')) AND (dc.parent_id=#{parentChannelId} OR dc.civil_code = #{parentChannelId}) AND dc.status= true AND dc.status= false AND dc.sub_count > 0 AND dc.sub_count = 0 AND dc.channel_id in
#{item}
ORDER BY dc.channel_id

select.foreach:
UPDATE wvp_device_channel SET update_time=#{item.updateTime}
   , name=#{item.name}
   , manufacture=#{item.manufacture}
   , model=#{item.model}
   , owner=#{item.owner}
   , civil_code=#{item.civilCode}
   , block=#{item.block}
   , sub_count=#{item.subCount}
   , address=#{item.address}
   , parental=#{item.parental}
   , parent_id=#{item.parentId}
   , safety_way=#{item.safetyWay}
   , register_way=#{item.registerWay}
   , cert_num=#{item.certNum}
   , certifiable=#{item.certifiable}
   , err_code=#{item.errCode}
   , secrecy=#{item.secrecy}
   , ip_address=#{item.ipAddress}
   , port=#{item.port}
   , password=#{item.password}
   , ptz_type=#{item.PTZType}
   , status=#{item.status}
   , stream_id=#{item.streamId}
   , has_audio=#{item.hasAudio}
   , longitude=#{item.longitude}
   , latitude=#{item.latitude}
   , longitude_gcj02=#{item.longitudeGcj02}
   , latitude_gcj02=#{item.latitudeGcj02}
   , longitude_wgs84=#{item.longitudeWgs84}
   , latitude_wgs84=#{item.latitudeWgs84}
   , business_group_id=#{item.businessGroupId}
   , gps_time=#{item.gpsTime}
   WHERE id=#{item.id}
   WHERE device_id=#{item.deviceId} AND channel_id=#{item.channelId}
